CREATE DATABASE IF NOT EXISTS yojanaconnect;
USE yojanaconnect;

DROP TABLE IF EXISTS schemes;
CREATE TABLE schemes (
    id VARCHAR(100) PRIMARY KEY,
    name TEXT NOT NULL,
    name_hindi TEXT NOT NULL,
    ministry TEXT NOT NULL,
    age_groups JSON NOT NULL,
    sectors JSON NOT NULL,
    income_limit INT NULL,
    categories JSON NOT NULL,
    benefit TEXT NOT NULL,
    description LONGTEXT NOT NULL,
    eligibility JSON NOT NULL,
    documents JSON NOT NULL,
    how_to_apply LONGTEXT NOT NULL,
    official_link TEXT NOT NULL,
    deadline VARCHAR(255),
    terms_and_conditions JSON NOT NULL,
    is_state TINYINT(1) NOT NULL DEFAULT 0,
    state VARCHAR(255),
    tags JSON NOT NULL,
    popularity_score INT NOT NULL DEFAULT 50
);

DROP TABLE IF EXISTS sectors;
CREATE TABLE sectors (
    id INT AUTO_INCREMENT PRIMARY KEY,
    sector_id VARCHAR(100) NOT NULL,
    name VARCHAR(255) NOT NULL,
    name_hindi VARCHAR(255) NOT NULL,
    age_groups JSON NOT NULL,
    icon VARCHAR(255) NOT NULL
);

