INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('pm-scholarship-001','PM Scholarship Scheme','पीएम छात्रवृत्ति योजना','Ministry of Education','["teen", "youngAdult"]','["education", "scholarship"]','800000','["general", "obc", "sc", "st"]','₹25,000/year scholarship','The Prime Minister''s Scholarship Scheme (PMSS) provides financial assistance to the wards and widows of Ex-Servicemen and Ex-Coast Guard personnel for pursuing professional degree courses. This landmark initiative ensures that the families of those who served the nation get equal access to quality higher education.\\n\\nThe scheme covers a wide range of professional courses including MBBS, BDS, BE, BTech, BEd, BBA, BCA, BPharma, Nursing, and other recognized professional courses. Students must be enrolled in government-recognized institutions.\\n\\nUnder this scheme, male scholars receive ₹2,500 per month and female scholars receive ₹3,000 per month, providing crucial financial support during their academic journey.','["Indian citizen", "Age 13-25", "Min 60% marks in last exam", "Ward/widow of Ex-Serviceman or Ex-Coast Guard", "Pursuing professional degree course", "Annual family income below ₹8 lakhs"]','["Aadhaar Card", "Income Certificate", "Marksheet (last qualifying exam)", "Bank Passbook", "Ex-Serviceman certificate", "Discharge certificate of parent"]','1. Visit the National Scholarship Portal at scholarships.gov.in\\n2. Register with your mobile number and Aadhaar\\n3. Fill the application form with your personal and academic details\\n4. Upload all required documents\\n5. Submit the application before the deadline\\n6. Track application status on the portal','https://scholarships.gov.in','31 December 2025','["Scholarship is renewable annually subject to satisfactory academic performance", "Minimum 60% marks required to continue receiving scholarship", "Scholar must not be receiving any other government scholarship", "Must inform the authority if leaving the course", "False information will lead to cancellation"]',0,NULL,'["education", "money", "scholarship", "ex-serviceman"]','95');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('nmmss-002','National Means-cum-Merit Scholarship','राष्ट्रीय साधन-सह-मेरिट छात्रवृत्ति','Ministry of Education','["teen"]','["education", "scholarship"]','150000','["general", "obc", "sc", "st"]','₹12,000/year scholarship for Class 9-12','The National Means-cum-Merit Scholarship Scheme (NMMSS) is a Centrally Sponsored Scheme to award scholarships to meritorious students of economically weaker sections to arrest their drop out at class VIII and encourage them to continue their education at secondary stage.\\n\\nThe scheme targets students who score a minimum of 55% marks (50% for SC/ST students) in class VII examination and continue the same in subsequent classes. Students studying in government, government-aided, and local body schools are eligible.\\n\\nOne lakh fresh scholarships are awarded every year to selected students of class IX at the rate of ₹12,000 per annum (₹1,000 per month) for study in classes IX to XII in State Government, Government-aided and local body schools.','["Indian citizen", "Studying in Class 9-12", "Min 55% in Class 7 (50% for SC/ST)", "Annual family income below ₹1.5 lakh", "Studying in Government or aided school"]','["Aadhaar Card", "Income Certificate", "Class 7 Marksheet", "Bank Passbook", "Caste Certificate (if applicable)", "School Certificate"]','1. Students are identified through a State Level Examination conducted by respective states\\n2. Apply through your school or state education department\\n3. Visit the National Scholarship Portal for online application\\n4. Submit required documents to school principal\\n5. School forwards applications to district education officer','https://scholarships.gov.in','30 November 2025','["Renewable annually with 55% marks (50% for SC/ST)", "Valid for studies in government schools only", "Scholar cannot receive other government scholarship simultaneously", "Must maintain regular attendance", "Suspension on poor academic performance"]',0,NULL,'["education", "merit", "scholarship", "school"]','88');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('bbbp-003','Beti Bachao Beti Padhao','बेटी बचाओ बेटी पढ़ाओ','Ministry of Women and Child Development','["teen"]','["education", "skill-training"]',NULL,'["general", "obc", "sc", "st"]','Financial support, education grants, and awareness programs for girl children','Beti Bachao Beti Padhao (BBBP) is a flagship scheme of the Government of India launched to address the declining Child Sex Ratio and related issues of women empowerment. The scheme aims to prevent gender-biased sex selective elimination, ensure survival and protection of the girl child, and promote education and participation of the girl child.\\n\\nThe scheme provides comprehensive support through convergent action of Ministries of Women and Child Development, Health & Family Welfare, and Human Resource Development. It covers financial incentives, conditional cash transfers, and community mobilization to support girls'' education and welfare.\\n\\nBenefits include scholarship support for girl students, awareness campaigns, and special schemes in districts with low sex ratio.','["Girl child, any age", "Indian citizen", "All income groups eligible", "Priority to districts with low sex ratio"]','["Birth certificate", "Aadhaar Card", "Bank account (Sukanya Samriddhi)", "School enrollment certificate"]','1. Visit the nearest Anganwadi centre or CSC (Common Service Centre)\\n2. Open a Sukanya Samriddhi Account at any Post Office or authorized bank\\n3. Deposit minimum ₹250 annually\\n4. Account matures when girl turns 21 or on marriage after age 18\\n5. Access scholarships through district education office','https://wcd.nic.in/bbbp-schemes',NULL,'["Sukanya Samriddhi Account must be opened before age 10", "Account can be continued till 21 years", "Partial withdrawal of 50% allowed after age 18 for education", "Premature closure only on death or life-threatening disease"]',0,NULL,'["girl child", "education", "women", "social"]','92');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('pmkvy-004','Pradhan Mantri Kaushal Vikas Yojana','प्रधानमंत्री कौशल विकास योजना','Ministry of Skill Development and Entrepreneurship','["teen", "youngAdult"]','["skill-training", "employment"]',NULL,'["general", "obc", "sc", "st"]','Free skill certification + ₹8,000 reward on certification','Pradhan Mantri Kaushal Vikas Yojana (PMKVY) is the flagship scheme of the Ministry of Skill Development & Entrepreneurship (MSDE). The objective of this Skill Certification Scheme is to enable a large number of Indian youth to take up industry-relevant skill training that will help them in securing a better livelihood.\\n\\nUnder this scheme, Training and Assessment fees are completely paid by the Government. Candidates who are already skilled but don''t have any formal certification can get Recognized Prior Learning (RPL) certification. PMKVY focuses on quality assurance, industry linkages, alignment with employer demand, and equipping the workforce with market-relevant skills.\\n\\nThe scheme provides monetary rewards for successful training and certification, covers 300+ job roles, and ensures placement support through its network of training partners.','["Indian citizen", "Age 15-45 years", "Unemployed or looking for skill upgrade", "Class 8 dropouts eligible for some courses", "Aadhar card mandatory"]','["Aadhaar Card", "Bank Passbook", "Passport size photograph", "Educational certificates", "Mobile number"]','1. Visit the official portal at pmkvyofficial.org\\n2. Find a PMKVY Training Centre near you\\n3. Choose from 300+ job roles in various sectors\\n4. Register at the training centre with required documents\\n5. Complete the training course (varies from a few days to months)\\n6. Appear for the certification exam\\n7. Receive certificate and monetary reward','https://pmkvyofficial.org',NULL,'["Training is completely free for candidates", "Monetary reward paid only after certification", "Must complete the full course and pass assessment", "Placement assistance available but not guaranteed", "Cannot enroll in same job role twice"]',0,NULL,'["skill", "training", "employment", "youth"]','90');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('pm-mudra-005','PM Mudra Yojana','प्रधानमंत्री मुद्रा योजना','Ministry of Finance','["youngAdult", "middleAge"]','["startup-business", "business-loans"]',NULL,'["general", "obc", "sc", "st", "women"]','Loans from ₹50,000 to ₹10 lakh without collateral','Pradhan Mantri MUDRA Yojana (PMMY) was launched to provide financial support to micro/small businesses. MUDRA stands for Micro Units Development & Refinance Agency. The scheme offers loans under three categories: Shishu (up to ₹50,000), Kishore (₹50,001–₹5 lakh), and Tarun (₹5,00,001–₹10 lakh).\\n\\nThese loans are given by Commercial Banks, RRBs, Small Finance Banks, MFIs, and NBFCs. The scheme primarily targets non-corporate, non-farm small/micro enterprises. Women entrepreneurs, SC/ST entrepreneurs, and minorities get priority and may receive lower interest rates.\\n\\nNo collateral is required for MUDRA loans, making it accessible for first-time entrepreneurs and small business owners who lack assets to pledge as security.','["Indian citizen", "Age 18 and above", "Non-corporate small business owner or entrepreneur", "Viable business plan required", "Good credit history preferred", "Not a defaulter on previous loans"]','["Aadhaar Card", "PAN Card", "Business plan/proof of business", "Bank statements (6 months)", "Proof of SC/ST/OBC (if applicable)", "Photographs", "Business registration (if any)"]','1. Approach any nationalized bank, RRB, cooperative bank, MFI, or NBFC\\n2. Fill the MUDRA loan application form\\n3. Submit business plan and required documents\\n4. Bank assesses the application\\n5. Loan sanctioned and disbursed to bank account\\n6. MUDRA card (debit card) issued for Shishu category','https://www.mudra.org.in',NULL,'["Interest rates vary by bank and loan category", "Repayment period up to 5 years", "No collateral required", "CIBIL score checked for Kishore and Tarun categories", "Can be used for business purposes only"]',0,NULL,'["loan", "business", "entrepreneur", "self-employment"]','96');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('startup-india-006','Startup India Seed Fund','स्टार्टअप इंडिया सीड फंड','Ministry of Commerce and Industry','["youngAdult", "middleAge"]','["startup-business"]',NULL,'["general", "obc", "sc", "st", "women"]','Up to ₹50 lakh seed funding for startups','The Startup India Seed Fund Scheme (SISFS) aims to provide financial assistance to startups for proof of concept, prototype development, product trials, market entry, and commercialization. This addresses the funding gap for early-stage startups who struggle to access traditional banking channels.\\n\\nThe scheme provides financial assistance of up to ₹50 lakh to startups through selected incubators across India. Grants of up to ₹20 lakh are provided for validation of proof of concept, prototype development, or product trials. Investments of up to ₹50 lakh are provided for market entry, commercialization, or scaling up.\\n\\nStartups selected through an inclusive process get this funding to build their minimum viable product, reach product-market fit, and demonstrate commercial viability to attract larger investments.','["DPIIT recognized startup", "Incorporated less than 2 years ago", "Must not have received more than ₹10 lakh funding from Government", "Startup must be working on innovative product/service", "Must be selected by empaneled incubator"]','["DPIIT recognition certificate", "Incorporation certificate", "Detailed business plan", "Pitch deck", "Bank account details", "Founders'' Aadhaar and PAN"]','1. Get DPIIT recognition at startupindia.gov.in\\n2. Apply through an empaneled incubator\\n3. Submit business plan and pitch deck\\n4. Present to incubator selection committee\\n5. If selected, sign agreement with incubator\\n6. Receive milestone-based funding','https://seedfund.startupindia.gov.in',NULL,'["Grant portion is non-repayable", "Investment portion may be converted to equity or royalty", "Funds must be used for stated business purposes", "Regular progress reports required", "IP created must remain with the startup"]',0,NULL,'["startup", "funding", "innovation", "entrepreneurship"]','82');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('pm-awas-007','PM Awas Yojana (Urban)','प्रधानमंत्री आवास योजना (शहरी)','Ministry of Housing and Urban Affairs','["youngAdult", "middleAge"]','["housing"]','1800000','["general", "obc", "sc", "st", "women"]','Up to ₹2.67 lakh subsidy on home loans','Pradhan Mantri Awas Yojana - Urban (PMAY-U) is a Housing for All initiative by the Government of India aiming to provide affordable housing to the urban poor. The mission addresses the housing requirement of urban poor including slum dwellers through four verticals: In-situ Slum Redevelopment (ISSR), Affordable Housing in Partnership (AHP), Beneficiary Led Construction (BLC), and Credit Linked Subsidy Scheme (CLSS).\\n\\nThe Credit Linked Subsidy Scheme (CLSS) component offers interest subsidy of 6.5% for Economically Weaker Section (EWS) and Low Income Group (LIG) on housing loan up to ₹6 lakh. For Middle Income Group (MIG-I), it''s 4% subsidy on loan up to ₹9 lakh, and MIG-II gets 3% on up to ₹12 lakh.\\n\\nBeneficiaries can avail benefits under this scheme if they do not own a pucca house in any part of India and have not previously availed any central government housing scheme.','["Indian citizen", "No pucca house in any part of India", "Annual income up to ₹18 lakh (MIG category)", "First-time home buyer", "Adult female member preferred as co-owner"]','["Aadhaar Card", "PAN Card", "Income proof", "Bank statements", "Property documents", "Self-declaration of no house ownership"]','1. Apply online at pmaymis.gov.in or through any empaneled bank/housing finance company\\n2. Select the appropriate income category (EWS/LIG/MIG)\\n3. Submit all required documents\\n4. Bank verifies eligibility and processes the loan\\n5. Subsidy is credited directly to your loan account\\n6. Track application status online','https://pmaymis.gov.in','31 December 2024','["Subsidy available only once per family", "Minimum 20 sq m carpet area for EWS", "Female ownership or co-ownership mandatory for EWS/LIG", "Interest subsidy is on Net Present Value basis", "Cannot combine with other housing subsidies"]',0,NULL,'["housing", "home loan", "subsidy", "urban"]','94');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('ayushman-bharat-008','Ayushman Bharat - PM Jan Arogya Yojana','आयुष्मान भारत - प्रधानमंत्री जन आरोग्य योजना','Ministry of Health and Family Welfare','["youngAdult", "middleAge", "senior"]','["health-insurance"]',NULL,'["general", "obc", "sc", "st"]','₹5 lakh health coverage per family per year','Ayushman Bharat Pradhan Mantri Jan Arogya Yojana (AB-PMJAY) is the world''s largest government-funded health insurance scheme. It provides a health cover of ₹5 lakh per family per year for secondary and tertiary care hospitalization to over 10.74 crore poor and vulnerable families (approximately 50 crore beneficiaries).\\n\\nThe scheme covers about 1,393 medical and surgical packages including surgery, medical and day care treatments, cost of medicines, diagnostics etc. Beneficiaries can avail cashless and paperless treatment at empaneled public and private hospitals across India.\\n\\nThe scheme uses a comprehensive list from SECC (Socio-Economic Caste Census) 2011 to identify beneficiaries. There is no cap on family size or age, ensuring even pre-existing conditions are covered from day one.','["Listed in SECC 2011 database", "No upper age limit", "No limit on family size", "Pre-existing conditions covered", "Portability across India"]','["Aadhaar Card", "Ration Card", "Family income proof", "SECC enrollment verification"]','1. Check eligibility at pmjay.gov.in or call 14555\\n2. Visit the nearest Ayushman Mitra at empaneled hospital\\n3. Verify through Aadhaar-based eKYC\\n4. Get Ayushman Bharat Golden Card issued\\n5. Present card at empaneled hospital for cashless treatment\\n6. No hospitalization expenses for covered treatments','https://pmjay.gov.in',NULL,'["Coverage is per family, not individual", "Hospitalization only (OPD not covered)", "Only at empaneled hospitals", "Pre-existing diseases covered from day 1", "Portability across all states/UTs"]',0,NULL,'["health", "insurance", "hospitalization", "medical"]','98');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('pm-kisan-009','PM Kisan Samman Nidhi','प्रधानमंत्री किसान सम्मान निधि','Ministry of Agriculture','["middleAge", "senior"]','["agriculture"]',NULL,'["general", "obc", "sc", "st"]','₹6,000/year in 3 installments directly to bank','PM-KISAN (Pradhan Mantri Kisan Samman Nidhi) is a central sector scheme with 100% funding from the Government of India. Under this scheme, financial benefit of ₹6000 per year is provided to all farmer families across the country in three equal installments of ₹2000 each, every four months.\\n\\nThe definition of family for the scheme is husband, wife and minor children. The state government and UT administration identifies the farmer families eligible to the scheme as per guidelines. The fund is directly transferred to the bank accounts of beneficiaries through DBT (Direct Benefit Transfer) mechanism.\\n\\nSmall and marginal farmers owning cultivable land up to 2 hectares were initially eligible, but now the scheme covers all landholding farmers.','["Farmer family owning cultivable land", "Land records must be in name of farmer", "Indian citizen", "No institutional land ownership", "Active bank account for DBT"]','["Aadhaar Card", "Land ownership documents", "Bank account passbook", "Kisan credit card (optional)"]','1. Register at pmkisan.gov.in\\n2. Or visit the nearest CSC (Common Service Centre)\\n3. Enter land and Aadhaar details\\n4. Submit land ownership documents\\n5. Registration is verified by state agriculture department\\n6. Once approved, installments directly credited to bank account','https://pmkisan.gov.in',NULL,'["Farmer must have valid land records", "Self-declaration required about land ownership", "Excluded if family member is government employee earning above threshold", "Must update Aadhaar linkage in bank account", "Penalty for incorrect declaration"]',0,NULL,'["farmer", "agriculture", "direct benefit", "income support"]','97');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('atal-pension-010','Atal Pension Yojana','अटल पेंशन योजना','Ministry of Finance','["youngAdult", "middleAge"]','["pension", "social-security"]',NULL,'["general", "obc", "sc", "st"]','Guaranteed pension ₹1,000–₹5,000/month after age 60','Atal Pension Yojana (APY) is a pension scheme primarily targeted at unorganised sector workers. Under the scheme, subscribers receive a guaranteed minimum pension of ₹1,000, ₹2,000, ₹3,000, ₹4,000 or ₹5,000 per month at the age of 60 years depending on their contribution.\\n\\nThe scheme is administered by the Pension Fund Regulatory and Development Authority (PFRDA). The contribution amount depends on the subscriber''s age at joining and the desired pension amount. The government co-contributes 50% of total contribution or ₹1,000 per annum, whichever is lower, for 5 years for those not covered under any statutory social security scheme and who are not income tax payers.\\n\\nOn the death of the subscriber, the same pension is paid to the spouse and after the death of both, the accumulated pension corpus is returned to the nominee.','["Indian citizen", "Age 18-40 years", "Active bank account with PFRDA-registered bank", "Not covered under any statutory social security scheme", "Not an income tax payer for government co-contribution benefit"]','["Aadhaar Card", "Bank account details", "Mobile number"]','1. Visit your bank branch where you have a savings account\\n2. Fill the APY registration form\\n3. Provide Aadhaar and bank account details\\n4. Choose the desired pension amount (₹1000-₹5000)\\n5. Set up auto-debit for contributions\\n6. Receive a PRAN (Permanent Retirement Account Number)','https://npscra.nsdl.co.in/atal-pension-yojana.php',NULL,'["Early exit allowed only in exceptional circumstances", "On death before 60, nominee can continue or withdraw", "Government co-contribution for non-tax payers only", "Auto-debit mandatory", "Penalty for insufficient balance"]',0,NULL,'["pension", "retirement", "financial security"]','85');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('pm-jan-dhan-011','PM Jan Dhan Yojana','प्रधानमंत्री जन धन योजना','Ministry of Finance','["youngAdult", "middleAge", "senior"]','["social-security"]',NULL,'["general", "obc", "sc", "st"]','Zero balance account + ₹2 lakh accident insurance + overdraft facility','Pradhan Mantri Jan Dhan Yojana (PMJDY) is the National Mission for Financial Inclusion that ensures access to financial services like banking, savings & deposit accounts, remittance, credit, insurance, pension in an affordable manner to the excluded sections.\\n\\nUnder this scheme, any unbanked person can open a bank account with zero balance. The account comes with a RuPay debit card with built-in accident insurance coverage of ₹2 lakh and life insurance cover of ₹30,000. An overdraft facility of up to ₹10,000 is available to eligible account holders.\\n\\nThe scheme has become the backbone of Direct Benefit Transfer (DBT) in India, enabling direct transfer of government benefits to the bank accounts of beneficiaries without any leakages.','["Indian citizen", "Age 10 years and above", "Unbanked individuals prioritized", "Valid identity proof required", "No minimum balance required"]','["Aadhaar Card", "Voter ID or Passport (alternative ID)", "Passport photograph"]','1. Visit any bank branch, Bank Mitra (BC), or CSC\\n2. Fill the account opening form\\n3. Submit identity proof (Aadhaar preferred)\\n4. Get RuPay debit card issued\\n5. Account opened with zero balance\\n6. Nominate a beneficiary for insurance claims','https://pmjdy.gov.in',NULL,'["Zero minimum balance unless overdraft used", "Overdraft facility only after 6 months of satisfactory account operation", "Insurance cover linked to RuPay card", "Nominee required for insurance claim", "Can link other benefits like PM-KISAN, pensions to this account"]',0,NULL,'["banking", "financial inclusion", "insurance", "DBT"]','93');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('ignoapss-012','Indira Gandhi National Old Age Pension Scheme','इंदिरा गांधी राष्ट्रीय वृद्धावस्था पेंशन योजना','Ministry of Rural Development','["senior"]','["pension", "old-age-support"]',NULL,'["general", "obc", "sc", "st"]','₹300-₹500/month pension (central component)','Indira Gandhi National Old Age Pension Scheme (IGNOAPS) is a social assistance scheme providing income support to the elderly poor in the form of pensions. This scheme is one of the sub-schemes under the National Social Assistance Programme (NSAP).\\n\\nThe central government provides ₹300 per month for persons aged 60-79 years and ₹500 per month for those aged 80 years and above who belong to households living below the poverty line. State governments are encouraged to add their own contribution on top of the central share, making the effective pension amount higher in many states.\\n\\nThe scheme aims to ensure that the elderly can live their final years with dignity and financial security, reducing their dependence on family and addressing old-age poverty.','["Indian citizen", "Age 60 years and above", "Below Poverty Line (BPL) category", "Has no or minimal means of subsistence from own source", "Not already getting pension from any other government source"]','["Aadhaar Card", "Age proof (birth certificate, school certificate)", "BPL certificate/Ration Card", "Bank passbook", "Passport photograph"]','1. Apply at the Gram Panchayat office (rural) or Ward office (urban)\\n2. Fill the pension application form\\n3. Submit age proof and BPL documents\\n4. Verification done by local authorities\\n5. Pension approved by District Collector/SDM\\n6. Amount credited directly to bank account','https://nsap.nic.in',NULL,'["Must be BPL cardholder", "Pension stops on death of beneficiary", "Annual verification of eligibility required", "Cannot get multiple pensions simultaneously", "Must report change in financial status"]',0,NULL,'["pension", "old age", "poverty", "social security"]','87');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('pmvvy-013','Pradhan Mantri Vaya Vandana Yojana','प्रधानमंत्री वय वंदना योजना','Ministry of Finance','["senior"]','["pension", "social-security"]',NULL,'["general", "obc", "sc", "st"]','Guaranteed 7.4% return on investment, up to ₹9,250/month pension','Pradhan Mantri Vaya Vandana Yojana (PMVVY) is an exclusive scheme for senior citizens providing old age income security. The scheme offers guaranteed return on investment of 7.4% per annum payable monthly (equivalent to 7.66% per annum effective) for 10 years to senior citizens aged 60 years and above.\\n\\nThe scheme is implemented through LIC of India. A maximum investment of ₹15 lakh is allowed per senior citizen, giving a maximum monthly pension of ₹9,250. The investment is exempt from Service Tax/GST. The interest income received from PMVVY is taxable.\\n\\nOn death of the pensioner during the policy term of 10 years, the purchase price (corpus) is refunded to the beneficiary. On survival at the end of the policy term, the purchase price (corpus) along with the final pension is payable.','["Indian citizen", "Age 60 years and above", "No upper age limit", "Investment of ₹1.5 lakh to ₹15 lakh", "Purchased through LIC of India"]','["Aadhaar Card", "Age proof", "Bank account details", "Cancelled cheque", "Photographs"]','1. Visit nearest LIC branch or apply online at licindia.in\\n2. Fill the PMVVY application form\\n3. Submit KYC documents\\n4. Pay the lump sum premium (investment amount)\\n5. Receive policy documents\\n6. Pension credited monthly to bank account','https://licindia.in/PMVVY','31 March 2023 (scheme closed for new subscribers)','["Loan facility available after 3 years (up to 75% of purchase price)", "Premature exit allowed on critical illness of self or spouse", "On premature exit, 98% of purchase price refunded", "Pension mode can be monthly, quarterly, half-yearly or yearly", "Investment up to ₹15 lakh per senior citizen"]',0,NULL,'["pension", "investment", "senior", "LIC"]','80');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('scss-014','Senior Citizens Savings Scheme','वरिष्ठ नागरिक बचत योजना','Ministry of Finance','["senior"]','["social-security", "pension"]',NULL,'["general", "obc", "sc", "st"]','8.2% interest per annum (highest among government schemes)','Senior Citizens Savings Scheme (SCSS) is a government-backed savings instrument for those aged 60 years and above. It is one of the most lucrative saving schemes for senior citizens offering an interest rate of 8.2% per annum, which is the highest among various guaranteed return investments.\\n\\nThe scheme offers quarterly interest payouts to provide regular income to senior citizens. The maximum deposit limit is ₹30 lakh per individual. The scheme has a tenure of 5 years which can be extended by another 3 years after maturity. Tax benefits are available under Section 80C of the Income Tax Act.\\n\\nSCSS is available at authorized post offices and banks across India. The scheme provides safe investment with assured returns, making it ideal for retired individuals looking for regular income.','["Indian citizen", "Age 60 years and above", "Retired civilian employees of age 55-60 also eligible", "Defence personnel from age 50 eligible", "NRIs and HUF not eligible"]','["Age proof", "Address proof", "PAN card", "Passport photographs", "Proof of retirement (for 55-60 age category)"]','1. Visit nearest post office or authorized bank\\n2. Fill SCSS account opening form\\n3. Submit KYC documents\\n4. Deposit amount (minimum ₹1,000, maximum ₹30 lakh)\\n5. Account opened immediately\\n6. Interest credited quarterly to linked savings account','https://www.indiapost.gov.in/Financial/pages/content/scss.aspx',NULL,'["Maximum deposit ₹30 lakh per account", "Joint account possible only with spouse", "Premature withdrawal allowed with penalty", "Extension for 3 years possible after 5-year maturity", "TDS deducted if annual interest exceeds ₹50,000"]',0,NULL,'["savings", "interest", "senior", "investment"]','83');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('pm-fasal-bima-015','PM Fasal Bima Yojana','प्रधानमंत्री फसल बीमा योजना','Ministry of Agriculture','["middleAge", "senior"]','["agriculture"]',NULL,'["general", "obc", "sc", "st"]','Crop insurance with minimum 2% premium for Kharif, 1.5% for Rabi','Pradhan Mantri Fasal Bima Yojana (PMFBY) provides comprehensive crop insurance to farmers against crop loss/damage due to unforeseen events. The scheme covers all food crops (cereals, millets and pulses), oilseeds, and annual commercial/horticultural crops.\\n\\nFarmers pay a very low premium - 2% for Kharif crops, 1.5% for Rabi crops, and 5% for commercial/horticultural crops. The remaining premium is shared equally between the central and state governments. This makes crop insurance affordable for even small and marginal farmers.\\n\\nThe scheme provides coverage from pre-sowing to post-harvest losses including prevented sowing, midseason adversity, post-harvest losses (up to 2 weeks), and localized calamities like hailstorm, landslide, and flood.','["Farmer growing notified crops in notified areas", "Both loanee and non-loanee farmers eligible", "Sharecroppers and tenant farmers also eligible", "Must have land records or valid tenancy agreement"]','["Land records/tenancy documents", "Aadhaar Card", "Bank account passbook", "Sowing certificate"]','1. Apply through your bank during crop season\\n2. Or visit nearest CSC/insurance company office\\n3. Or apply online at pmfby.gov.in\\n4. Submit land and crop details\\n5. Pay the applicable premium\\n6. Claim process initiated automatically on notified calamities through satellite/crop cutting experiments','https://pmfby.gov.in',NULL,'["Mandatory for farmers taking Kisan Credit Card loans", "Enrollment must be done before cutoff date each season", "Claims settled through Remote Sensing and Crop Cutting Experiments", "Area approach for coverage (block/village level losses)", "Individual farm losses for localized calamities"]',0,NULL,'["farmer", "agriculture", "insurance", "crop"]','86');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('stand-up-india-016','Stand-Up India','स्टैंड अप इंडिया','Ministry of Finance','["youngAdult", "middleAge"]','["startup-business", "business-loans"]',NULL,'["sc", "st", "women"]','Loans ₹10 lakh to ₹1 crore for SC/ST/Women entrepreneurs','Stand-Up India scheme facilitates bank loans between ₹10 lakh and ₹1 crore to at least one Scheduled Caste (SC) or Scheduled Tribe (ST) borrower and at least one woman borrower per bank branch for setting up a greenfield enterprise.\\n\\nThis enterprise may be in manufacturing, services, agri-allied activities, or trading sector. In case of non-individual enterprises, at least 51% of the shareholding and controlling stake should be held by either an SC/ST or Woman entrepreneur.\\n\\nThe scheme provides handholding support including credit guarantee cover through NCGTC, refinancing window through SIDBI, and a web portal for credit facilitation. The scheme aims to leverage the institutional credit structure to reach underserved sections of society.','["SC/ST or woman entrepreneur", "Age 18 years and above", "Setting up a greenfield enterprise", "Not in default to any bank/financial institution", "Business in manufacturing, services or trading"]','["Aadhaar Card", "PAN Card", "Caste certificate (for SC/ST)", "Business plan", "Bank statements", "Property documents (if any)", "Proof of non-default"]','1. Apply at nearest bank branch (all scheduled commercial banks)\\n2. Or apply online through standupmitra.in portal\\n3. Submit business plan and KYC documents\\n4. Bank evaluates business viability\\n5. Get handholding support if needed\\n6. Loan disbursed on approval','https://www.standupmitra.in',NULL,'["Loan tenure up to 7 years", "Working capital limit as CC up to ₹10 lakh", "Composite loan (term loan + working capital)", "Collateral as per bank norms or NCGTC cover", "For greenfield enterprises only"]',0,NULL,'["loan", "SC/ST", "women", "entrepreneur", "startup"]','79');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('pm-svanidhi-017','PM SVANidhi Scheme','पीएम स्वनिधि योजना','Ministry of Housing and Urban Affairs','["middleAge", "senior", "youngAdult"]','["startup-business", "business-loans"]',NULL,'["general", "obc", "sc", "st"]','Working capital loan ₹10,000–₹50,000 for street vendors','PM Street Vendor''s AtmaNirbhar Nidhi (PM SVANidhi) scheme provides affordable working capital loans to street vendors who have been adversely impacted due to Covid-19 lockdown, enabling them to restart their livelihoods.\\n\\nUnder this scheme, vendors can avail a collateral-free working capital loan of ₹10,000 initially, which on timely repayment can be enhanced to ₹20,000 and ₹50,000 in subsequent loan cycles. Digital transactions are incentivized through cashback of up to ₹1,200 per annum. Vendors are also covered under social security schemes.\\n\\nThe scheme targets about 50 lakh street vendors in urban areas including vendors operating in surrounding peri-urban or rural areas. The scheme helps vendors graduate from debt traps of moneylenders to formal banking system.','["Street vendor in urban areas", "Vending on or before 24 March 2020", "Certificate of Vending or Letter of Recommendation from ULB", "Any category eligible", "Indian citizen"]','["Aadhaar Card", "Certificate of Vending / Letter of Recommendation", "Bank account details", "Photographs"]','1. Apply through pmsvanidhi.mohua.gov.in or mobile app\\n2. Or apply at MFI/NBFC/SHG/Cooperative/Scheduled Commercial Bank\\n3. Get Certificate of Vending from Urban Local Body (ULB)\\n4. Submit application with documents\\n5. Loan disbursed quickly (usually within 30 days)\\n6. Digital payments incentivized with cashback','https://pmsvanidhi.mohua.gov.in',NULL,'["Loan tenure: 1 year for ₹10,000, 18 months for ₹20,000, 36 months for ₹50,000", "Interest subvention of 7% per annum", "Digital transaction cashback up to ₹1,200 per year", "Timely repayment required for enhanced loans", "Credit score built for future lending"]',0,NULL,'["street vendor", "loan", "working capital", "urban"]','81');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('inspire-018','INSPIRE Scholarship for Higher Education','इंस्पायर उच्च शिक्षा छात्रवृत्ति','Department of Science & Technology','["teen", "youngAdult"]','["education", "scholarship"]',NULL,'["general", "obc", "sc", "st"]','₹80,000/year scholarship for 5 years (BSc/BS/Int. MSc courses)','Innovation in Science Pursuit for Inspired Research (INSPIRE) is a national programme implemented by the Department of Science & Technology. The Scholarship for Higher Education (SHE) component aims to attract talented youth to study science at the undergraduate and postgraduate level.\\n\\nTop 1% students in Class XII Board exams and toppers in various merit lists are eligible. The scholarship is ₹80,000 per year for 5 years, covering the complete duration of BSc/BS/Integrated MSc/MS programmes.','["Indian citizen", "Top 1% in Class XII Board exam or equivalent merit list", "Pursuing BSc/BS/Integrated MSc in Natural/Basic Sciences", "Admitted in recognized Indian institution", "Age up to 22 years at time of joining"]','["Aadhaar Card", "Class XII Marksheet & Certificate", "Admission proof from recognized institution", "Bank Passbook", "Passport photograph"]','1. Check eligibility on online-inspire.gov.in\\n2. Submit online application with required documents\\n3. Verification done by DST\\n4. Scholarship credited annually to bank account\\n5. Mentorship from senior scientists provided','https://online-inspire.gov.in','30 September each year','["Must pursue science courses only", "Renewal subject to satisfactory academic performance", "Cannot combine with other DST scholarships", "Must maintain 60% marks each year"]',0,NULL,'["science", "scholarship", "higher education", "research"]','77');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('khelo-india-019','Khelo India Youth Games','खेलो इंडिया यूथ गेम्स','Ministry of Youth Affairs and Sports','["teen"]','["sports"]',NULL,'["general", "obc", "sc", "st"]','₹5 lakh/year scholarship for 8 years for identified athletes','Khelo India is the flagship programme of the Ministry of Youth Affairs and Sports to revive the sports culture in India at the grassroots level. The programme provides financial support of ₹5 lakh per year for 8 years to athletes identified as talented during the Khelo India Games.\\n\\nThe scheme covers 20+ sports disciplines, provides world-class training facilities, sports science support, and helps athletes build a career in sports while continuing their education.','["Indian citizen", "Age 8-18 years", "Identified as talented athlete at Khelo India Games", "Pursuing formal education", "Recommended by State Sports Authority"]','["Birth Certificate", "Aadhaar Card", "Sports achievement certificates", "School enrollment certificate", "Photograph", "Bank account details"]','1. Participate in Khelo India Youth Games (held annually)\\n2. Outperform and get selected by expert committee\\n3. Get recommendation from State Sports Association\\n4. Apply at the Khelo India portal kheloindia.gov.in\\n5. Annual scholarship disbursed directly to bank account','https://kheloindia.gov.in',NULL,'["Must continue formal education alongside sports training", "Annual performance review for scholarship renewal", "Must represent India in national/international competitions when selected", "Cannot receive other government sports scholarship simultaneously"]',0,NULL,'["sports", "athlete", "youth", "scholarship"]','73');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('pm-poshan-020','PM POSHAN Scheme (Mid-Day Meal)','पीएम पोषण शक्ति निर्माण योजना','Ministry of Education','["teen"]','["education"]',NULL,'["general", "obc", "sc", "st"]','Free nutritious mid-day meal at school every day','PM POSHAN Shakti Nirman (formerly Mid-Day Meal Scheme) is the world''s largest school feeding programme, providing hot cooked meals to students of Classes 1 to 8 in government and aided schools. The scheme covers about 12 crore children across 11.5 lakh schools.\\n\\nNutritious meals reduce hunger and improve attendance, enrolment, and retention. The scheme also provides additional nutrition for children from disadvantaged backgrounds, with menus prescribed by nutritionists.','["Students of Class 1-8", "Studying in government or government-aided school", "Automatically eligible – no application needed", "All categories"]','["School enrollment (automatic benefit)", "No separate documents required"]','1. Enroll your child in any government or aided school\\n2. The school automatically provides the mid-day meal every school day\\n3. No separate application required\\n4. Parents can check menu and quality through School Management Committee','https://pmposhan.education.gov.in',NULL,'["Available only on school days", "Meal must meet prescribed nutritional norms", "Cooking must be done in clean hygienic environment", "States can supplement with additional items"]',0,NULL,'["nutrition", "school", "meal", "children"]','85');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('pre-matric-sc-021','Pre-Matric Scholarship for SC Students','एससी छात्रों के लिए प्री-मैट्रिक छात्रवृत्ति','Ministry of Social Justice and Empowerment','["teen"]','["education", "scholarship"]','250000','["sc"]','₹150-₹350/month + book grant ₹750-₹1000/year','Pre-Matric Scholarship for SC students supports Scheduled Caste students studying in Classes 9 and 10 to prevent dropout and encourage continuation of education. The scholarship covers maintenance allowance, reader allowance for blind students, and additional allowances for disabled students.\\n\\nDay scholars receive ₹150/month (Class 9) or ₹160/month (Class 10), while hostellers receive ₹350/month, plus a book grant of ₹750 per annum.','["Scheduled Caste student", "Studying in Class 9 or 10", "Annual family income below ₹2.5 lakh", "Indian citizen", "Not receiving other scholarship"]','["Aadhaar Card", "Caste Certificate (SC)", "Income Certificate", "Previous class Marksheet", "Bank Passbook", "School Certificate"]','1. Apply through National Scholarship Portal scholarships.gov.in\\n2. Or apply through State Social Welfare Department\\n3. Get school principal''s recommendation\\n4. Submit all documents before deadline\\n5. Track status on portal','https://scholarships.gov.in','31 October each year','["Must score minimum 55% in previous class", "Scholarship stops if student fails twice in same class", "Must not receive other central government scholarship", "Disciplinary action can lead to cancellation"]',0,NULL,'["SC", "scholarship", "pre-matric", "school"]','80');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('pm-ujjwala-022','PM Ujjwala Yojana 2.0','प्रधानमंत्री उज्ज्वला योजना 2.0','Ministry of Petroleum and Natural Gas','["youngAdult", "middleAge"]','["social-security"]',NULL,'["general", "obc", "sc", "st"]','Free LPG connection + first refill free + stove free','Pradhan Mantri Ujjwala Yojana 2.0 provides free LPG connections to adult women of Below Poverty Line households who do not already have a connection. The scheme aims to replace polluting cooking fuels with cleaner LPG.\\n\\nBeneficiaries get a free LPG connection, first refill free, and a free stove (in many cases). Migrant workers can get connections even without permanent address proof by submitting a self-declaration.','["Adult woman (age 18+)", "BPL household or SECC listed", "No existing LPG connection in household", "Indian citizen", "Active bank account required"]','["Aadhaar Card", "Ration Card / BPL Certificate", "Bank account passbook", "Address proof (self-declaration for migrants)", "Photograph"]','1. Visit the nearest LPG distributor (HP/Bharat/Indane Gas)\\n2. Fill the KYC form and application form\\n3. Submit documents including Aadhaar and BPL proof\\n4. Connection issued immediately on verification\\n5. First refill and stove provided free','https://pmuy.gov.in',NULL,'["Only one connection per household", "Must be in woman''s name", "Subsequent refills at market price (EMI option available)", "Cannot transfer connection to another person"]',0,NULL,'["LPG", "cooking gas", "women", "BPL"]','91');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('e-shram-023','e-SHRAM Card Registration','ई-श्रम कार्ड पंजीकरण','Ministry of Labour and Employment','["youngAdult", "middleAge"]','["social-security", "employment"]',NULL,'["general", "obc", "sc", "st"]','Free accident insurance ₹2 lakh + access to all social security schemes','e-SHRAM is the national database of unorganised workers in India. Registering on e-SHRAM gives workers a Unique Worker Identification Number (UWIN) and access to social security benefits.\\n\\nRegistered workers get ₹2 lakh accident insurance under PM Suraksha Bima Yojana free for one year. The card helps workers access welfare schemes, get priority in future government benefits, and build a verified work history.','["Unorganised sector worker", "Age 16-59 years", "Not a member of EPFO or ESIC", "Indian citizen", "Active mobile number linked to Aadhaar"]','["Aadhaar Card", "Bank account linked to Aadhaar", "Mobile number linked to Aadhaar"]','1. Visit eshram.gov.in and click ''Register on e-SHRAM''\\n2. Enter Aadhaar-linked mobile number\\n3. Verify with OTP\\n4. Fill occupation and bank details\\n5. Download e-SHRAM card instantly\\n6. Card can also be made at CSC','https://eshram.gov.in',NULL,'["Registration is completely free", "Must update profile periodically", "Accident insurance valid for 1 year, renewable", "Workers can link multiple occupations"]',0,NULL,'["unorganised worker", "social security", "insurance", "registration"]','84');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('pmsym-024','PM Shram Yogi Maan-dhan','प्रधानमंत्री श्रम योगी मान-धन','Ministry of Labour and Employment','["youngAdult", "middleAge"]','["pension", "social-security"]','1500000','["general", "obc", "sc", "st"]','Guaranteed ₹3,000/month pension after age 60','PM Shram Yogi Maan-dhan (PM-SYM) is a pension scheme for unorganised sector workers providing assured monthly pension of ₹3,000 after attaining the age of 60 years, on a minimum contribution of as low as ₹55/month.\\n\\nThe central government matches every contribution made by the subscriber. Workers in informal sector like street vendors, rickshaw pullers, construction workers, domestic workers benefit most from this scheme.','["Unorganised sector worker", "Age 18-40 years at enrollment", "Monthly income up to ₹15,000", "Not covered under NPS/EPFO/ESIC", "Active bank account and mobile number"]','["Aadhaar Card", "Bank Savings Account passbook", "Mobile number"]','1. Visit nearest CSC (Common Service Centre)\\n2. Or enroll through maandhan.in portal\\n3. Bring Aadhaar and bank passbook\\n4. Contribution auto-deducted monthly from bank account\\n5. Receive PM-SYM pension card','https://maandhan.in',NULL,'["Government matches every rupee contribution", "Monthly contribution ranges ₹55–₹200 depending on age", "On death, spouse gets 50% of pension", "Exit before 60: get back own contribution with interest", "Cannot receive other pension scheme benefits"]',0,NULL,'["pension", "unorganised worker", "retirement", "social security"]','79');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('nps-025','National Pension System (NPS)','राष्ट्रीय पेंशन प्रणाली','Ministry of Finance / PFRDA','["youngAdult", "middleAge"]','["pension"]',NULL,'["general", "obc", "sc", "st"]','Market-linked pension savings + 60% lump sum tax-free at retirement','National Pension System (NPS) is a voluntary, defined contribution retirement savings scheme to enable subscribers to make optimum decisions regarding their future through systematic savings during their working life.\\n\\nSubscribers can withdraw 60% of the corpus as lump sum (tax-free) on retirement, with 40% used to buy an annuity for monthly pension. Additional tax deduction of ₹50,000 under Section 80CCD(1B) over and above ₹1.5 lakh under 80C.','["Indian citizen", "Age 18-70 years", "Both salaried and self-employed eligible", "NRIs also eligible", "KYC compliant"]','["Aadhaar Card", "PAN Card", "Bank account details", "Photograph", "Cancelled cheque"]','1. Open NPS account at any Point of Presence (PoP) – banks, post offices\\n2. Or apply online at enps.nsdl.com\\n3. Get PRAN (Permanent Retirement Account Number)\\n4. Make minimum contribution of ₹500 (Tier I)\\n5. Choose investment fund manager and asset mix\\n6. Monitor and contribute regularly','https://npscra.nsdl.co.in',NULL,'["Minimum contribution ₹1,000 per year in Tier I", "Partial withdrawal allowed for specified purposes after 3 years", "Full withdrawal allowed at 60 years", "60% tax-free lump sum at retirement", "40% must be used for annuity"]',0,NULL,'["pension", "retirement", "investment", "tax savings"]','81');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('ddu-gky-026','Deen Dayal Upadhyaya Grameen Kaushalya Yojana','दीन दयाल उपाध्याय ग्रामीण कौशल्य योजना','Ministry of Rural Development','["youngAdult", "teen"]','["skill-training", "employment"]',NULL,'["general", "obc", "sc", "st"]','Free residential skill training + placement in formal sector jobs','DDU-GKY is a placement-linked, demand-driven rural skill training programme that targets rural youth between the age of 15-35 years. The programme trains rural youth in various skills and provides placement in private sector jobs with wages above minimum wage.\\n\\nThe scheme provides free residential training, accommodation, meals, uniform, and tools. Post-training, candidates are placed in jobs with a salary of at least ₹6,000/month. The programme focuses on SC/ST/minorities and women.','["Rural youth", "Age 15-35 years (up to 45 for specially abled and women)", "Family member of MGNREGS job card holder preferred", "SC/ST/minorities/women given priority", "No minimum education requirement for most trades"]','["Aadhaar Card", "MGNREGS Job Card (if applicable)", "Caste Certificate", "Education certificate (if available)", "Bank passbook", "Photograph"]','1. Contact your Gram Panchayat or Block Development Office\\n2. Or visit nearest DDU-GKY Training Centre\\n3. Or apply online at skillindiadigital.gov.in\\n4. Attend awareness camp for scheme details\\n5. Complete enrollment with documents\\n6. Training starts in residential campus','https://skillindiadigital.gov.in',NULL,'["Training is completely free including accommodation and meals", "Must attend minimum 80% training sessions", "Placement guaranteed in formal sector", "Post-placement support for 1 year", "Must maintain job for minimum 3 months"]',0,NULL,'["skill training", "rural", "placement", "employment", "youth"]','76');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('kisan-credit-card-027','Kisan Credit Card (KCC)','किसान क्रेडिट कार्ड','Ministry of Agriculture & Farmers Welfare','["middleAge", "senior"]','["agriculture", "business-loans"]',NULL,'["general", "obc", "sc", "st"]','Short-term credit up to ₹3 lakh at 4% interest (subsidized)','Kisan Credit Card (KCC) provides farmers with timely and adequate credit for their agricultural operations at concessional interest rates. Farmers can borrow up to ₹3 lakh at 4% per annum interest (after 3% interest subvention) for crop loans.\\n\\nThe card also provides credit for post-harvest expenses, maintenance of farm assets, and consumption requirements. KCC acts like a revolving credit facility with a 5-year validity.','["Farmer, sharecropper, or tenant farmer", "Allied activities like animal husbandry and fisheries also eligible", "Indian citizen", "No default on agricultural loans", "Viable agricultural land or activity"]','["Aadhaar Card", "Land ownership/tenancy documents", "Bank account details", "Passport photograph", "PAN Card (for loans above ₹1 lakh)"]','1. Visit your nearest bank branch (all commercial banks and cooperative banks)\\n2. Fill the KCC application form\\n3. Submit land documents and KYC papers\\n4. Bank assesses creditworthiness and land holding\\n5. KCC issued within 2 weeks of application\\n6. ATM card for cash withdrawal also provided','https://www.nabard.org/content1.aspx?id=572&catid=23&mid=530',NULL,'["Credit limit based on land holding and crop pattern", "Repayment within 12 months of each disbursement", "Annual review of credit limit", "Crop insurance mandatory", "Interest subvention only if repaid on time"]',0,NULL,'["farmer", "credit", "agriculture", "loan"]','89');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('msme-eclgs-028','Emergency Credit Line Guarantee Scheme (ECLGS)','आपातकालीन क्रेडिट लाइन गारंटी योजना','Ministry of Finance','["middleAge", "youngAdult"]','["business-loans", "startup-business"]',NULL,'["general", "obc", "sc", "st"]','100% government guarantee on additional loans up to 20% of outstanding credit','The Emergency Credit Line Guarantee Scheme (ECLGS) provides additional credit of up to 20% of outstanding credit to MSMEs and business enterprises at a capped interest rate of 9.25% for banks and 14% for NBFCs.\\n\\nThe scheme provides 100% credit guarantee, meaning MSMEs don''t need additional collateral. Repayment period is 4 years including a 12-month moratorium on principal repayment.','["MSME or business enterprise", "Outstanding credit up to ₹50 crore (for ECLGS 1.0)", "No NPA (Non-Performing Asset) as of February 2020", "GST registered preferred", "Indian entity"]','["GST registration", "Business financial statements", "Existing loan documents", "Aadhaar and PAN of proprietor/directors", "Bank account details"]','1. Contact your existing bank/NBFC where you have business loan\\n2. They will check your eligibility automatically\\n3. Fill the ECLGS application form\\n4. Bank processes and disburses additional credit\\n5. No additional collateral required','https://www.ncgtc.in',NULL,'["Moratorium on principal for 12 months", "No prepayment penalty", "Available only through existing lenders", "GST returns to be submitted regularly", "Business must be operational"]',0,NULL,'["MSME", "business", "credit", "emergency", "loan"]','75');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('pm-awas-rural-029','PM Awas Yojana (Gramin)','प्रधानमंत्री आवास योजना (ग्रामीण)','Ministry of Rural Development','["middleAge", "youngAdult", "senior"]','["housing"]',NULL,'["general", "obc", "sc", "st"]','₹1.2–1.3 lakh grant for constructing a pucca house (plain areas); ₹1.3 lakh (hilly/NE states)','Pradhan Mantri Awaas Yojana – Gramin (PMAY-G) aims to achieve ''Housing for All'' in rural areas by providing assistance to BPL families for construction of safe and durable houses. Each beneficiary gets a grant of ₹1.20 lakh (plain areas) or ₹1.30 lakh (hilly/NE/IAP districts).\\n\\nBeneficiaries also get 90 person-days of unskilled labour under MGNREGS. All payments are made directly to bank accounts. Construction is monitored through geo-tagged photographs.','["Houseless or living in kutcha/dilapidated house", "Listed in SECC 2011 permanent wait list or Awaas+ survey", "SC/ST/OBC/minorities get priority", "Must have a functional toilet (can be built under Swachh Bharat)", "Rural resident"]','["Aadhaar Card", "SECC/Awaas+ listing proof", "Bank account passbook", "Photograph of existing dwelling", "Caste certificate (if applicable)"]','1. Eligibility automatically determined from SECC 2011 data\\n2. Beneficiaries informed through Gram Sabha\\n3. Register at pmayg.nic.in or through Gram Panchayat\\n4. Complete the application with Gram Panchayat assistance\\n5. Funds released in installments based on construction progress\\n6. Progress monitored through AwaasSoft mobile app','https://pmayg.nic.in',NULL,'["House must be completed within 12 months of first installment", "Must include toilet as per Swachh Bharat Abhiyan", "Beneficiary must construct themselves or with hired labour", "Cannot sell or transfer property for 10 years", "Progress monitored through geo-tagged photos"]',0,NULL,'["housing", "rural", "pucca house", "BPL", "construction"]','91');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('pm-suraksha-bima-030','PM Suraksha Bima Yojana','प्रधानमंत्री सुरक्षा बीमा योजना','Ministry of Finance','["youngAdult", "middleAge"]','["social-security", "health-insurance"]',NULL,'["general", "obc", "sc", "st"]','₹2 lakh accidental death & disability insurance at only ₹20/year','PM Suraksha Bima Yojana (PMSBY) provides accidental death and disability insurance at an annual premium of just ₹20. The scheme offers ₹2 lakh cover for accidental death or total permanent disability, and ₹1 lakh for partial permanent disability.\\n\\nThe premium is auto-debited from the bank account on or before 1st June each year. It is one of the most affordable insurance schemes in the world.','["Indian citizen", "Age 18-70 years", "Savings bank account", "Aadhaar linked to bank account preferred", "Auto-debit consent given"]','["Aadhaar Card", "Savings bank account details", "Mobile number"]','1. Visit your bank branch or net banking portal\\n2. Fill the PMSBY application form\\n3. Give auto-debit consent for ₹20 annual premium\\n4. Enrollment valid from 1 June to 31 May\\n5. Coverage starts immediately on enrollment\\n6. Claim through bank in case of accident','https://jansuraksha.gov.in',NULL,'["Annual renewal required", "Coverage excludes self-inflicted injuries", "Claim must be made within 30 days of accident", "Both accidental death and disability covered", "Maximum 2 accounts per individual"]',0,NULL,'["insurance", "accident", "cheap insurance", "social security"]','88');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('pm-jeevan-jyoti-031','PM Jeevan Jyoti Bima Yojana','प्रधानमंत्री जीवन ज्योति बीमा योजना','Ministry of Finance','["youngAdult", "middleAge"]','["social-security"]',NULL,'["general", "obc", "sc", "st"]','₹2 lakh life insurance at only ₹436/year','PM Jeevan Jyoti Bima Yojana (PMJJBY) offers renewable term life insurance covering death from any cause at an annual premium of ₹436. The scheme provides ₹2 lakh to the nominee in case of the policy holder''s death.\\n\\nThe premium is auto-debited from the bank account. This is one of the cheapest term insurance schemes offered by the government.','["Indian citizen", "Age 18-50 years", "Savings bank account", "Consent for auto-debit", "Can join up to age 55 if enrolled before 50"]','["Aadhaar Card", "Bank savings account details", "Nominee details", "Mobile number"]','1. Visit bank branch or net banking\\n2. Fill PMJJBY enrollment form\\n3. Nominate a family member\\n4. Give auto-debit consent for ₹436/year\\n5. Coverage valid for 1 year (June to May)\\n6. Claim processed through bank by nominee','https://jansuraksha.gov.in',NULL,'["Annual renewal mandatory", "Coverage for death from any cause", "Suicide in first year not covered", "Claim by nominee within 30 days of death", "Cannot have more than one PMJJBY policy"]',0,NULL,'["life insurance", "term insurance", "death benefit", "social security"]','86');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('pm-garib-kalyan-032','PM Garib Kalyan Anna Yojana','प्रधानमंत्री गरीब कल्याण अन्न योजना','Ministry of Food and Consumer Affairs','["middleAge", "senior", "youngAdult"]','["social-security"]',NULL,'["general", "obc", "sc", "st"]','5 kg free food grains per person per month','PM Garib Kalyan Anna Yojana (PMGKAY) provides 5 kg of free food grains (rice/wheat/coarse grains) per person per month to beneficiaries under the National Food Security Act (NFSA).\\n\\nThe scheme covers about 81.35 crore beneficiaries under NFSA. Food grains are distributed through the Public Distribution System (PDS) via Fair Price Shops.','["Listed under National Food Security Act (NFSA)", "Antodaya Anna Yojana (AAY) card holder", "Priority Household (PHH) card holder", "Any category (no income restriction for NFSA listed)"]','["Ration Card", "Aadhaar Card", "Registration in NFSA system"]','1. If not already listed in NFSA, apply at State Food Department\\n2. Existing NFSA beneficiaries automatically covered\\n3. Collect food grains from designated Fair Price Shop (ration shop)\\n4. Show Aadhaar for biometric verification at PDS shop\\n5. No separate application needed for existing beneficiaries','https://dfpd.gov.in/pmgkay.htm',NULL,'["Available at designated Fair Price Shops only", "Monthly allocation per eligible family", "Ration card and Aadhaar required for collection", "Cannot collect on behalf of others without authorization"]',0,NULL,'["food security", "ration", "free food", "PDS"]','96');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('rashtriya-vayoshri-033','Rashtriya Vayoshri Yojana','राष्ट्रीय वयोश्री योजना','Ministry of Social Justice and Empowerment','["senior"]','["old-age-support", "health-insurance"]',NULL,'["general", "obc", "sc", "st"]','Free assistive living devices (walking sticks, wheelchairs, hearing aids, spectacles)','Rashtriya Vayoshri Yojana (RVY) provides physical aids and assistive living devices to senior citizens belonging to BPL category who suffer from age-related disabilities/infirmities. The scheme ensures that poor senior citizens live with dignity and independence.\\n\\nAssistive devices include walking sticks, elbow crutches, walkers/crutches, tripods/quadpods, hearing aids, wheelchairs, artificial dentures, and spectacles. All devices conform to BIS standards.','["Senior citizen aged 60 years and above", "Below Poverty Line (BPL) category", "Must suffer from age-related disabilities", "Indian citizen", "Residing in India"]','["Aadhaar Card", "Age proof", "BPL Ration Card", "Medical certificate of disability/infirmity", "Photograph"]','1. Contact the District Social Welfare Officer or nearby CSC\\n2. Or apply through Artificial Limbs Manufacturing Corporation (ALIMCO)\\n3. Medical screening camps held in districts\\n4. Devices distributed free at camp sites\\n5. Apply also at socialjustice.gov.in','https://socialjustice.gov.in/schemes/73',NULL,'["One-time provision of devices per beneficiary", "Devices replaced only after prescribed life period", "Must be BPL to qualify", "Medical screening mandatory for device selection"]',0,NULL,'["senior", "disability", "assistive devices", "BPL"]','71');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('igndps-034','Indira Gandhi National Disability Pension Scheme','इंदिरा गांधी राष्ट्रीय विकलांगता पेंशन योजना','Ministry of Rural Development','["middleAge", "senior"]','["old-age-support", "social-security"]',NULL,'["general", "obc", "sc", "st"]','₹300/month central pension (state may add more)','Indira Gandhi National Disability Pension Scheme (IGNDPS) provides monthly pension to severely disabled persons from BPL households. The central government provides ₹300/month, and states supplement with additional amounts.\\n\\nThe scheme covers persons with severe or multiple disabilities (80% or more disability) aged 18 years and above.','["Person with severe or multiple disabilities (80%+ disability)", "Age 18 years and above", "BPL household", "Indian citizen", "Disability certified by government medical board"]','["Aadhaar Card", "Disability Certificate (80%+) from govt hospital", "BPL Certificate/Ration Card", "Age proof", "Bank passbook", "Photograph"]','1. Apply at Gram Panchayat (rural) or Ward Office (urban)\\n2. Submit disability certificate from government medical board\\n3. Verification by local authorities\\n4. Approved by District Collector\\n5. Pension credited directly to bank account','https://nsap.nic.in',NULL,'["Disability must be 80% or more as certified", "Annual verification required", "Cannot receive alongside old age pension", "Pension stops if disability reduces below 80%"]',0,NULL,'["disability", "pension", "BPL", "social security"]','68');
INSERT INTO schemes (id,name,name_hindi,ministry,age_groups,sectors,income_limit,categories,benefit,description,eligibility,documents,how_to_apply,official_link,deadline,terms_and_conditions,is_state,state,tags,popularity_score) VALUES ('annapurna-035','Annapurna Scheme','अन्नपूर्णा योजना','Ministry of Rural Development','["senior"]','["old-age-support", "social-security"]',NULL,'["general", "obc", "sc", "st"]','10 kg free food grain per month to destitute seniors','The Annapurna Scheme provides 10 kg of food grains per month free of cost to destitute senior citizens who are not getting pension under any state or central pension scheme despite being eligible. It targets those who have ''slipped through the net'' of other schemes.\\n\\nThe scheme covers those who are aged 65 years and above, eligible for old age pension but not getting it.','["Senior citizen aged 65 years and above", "Destitute (no regular income or financial support)", "Not already getting old age pension", "Not covered under NFSA/TPDS", "BPL household"]','["Aadhaar Card", "Age proof", "BPL certificate", "Self-declaration of no pension", "Photograph"]','1. Apply at Gram Panchayat (rural) or Ward Office (urban)\\n2. Submit age proof and BPL documents\\n3. Self-declare that no pension is being received\\n4. Approved by District Collector\\n5. Food grains collected from designated Fair Price Shop','https://nsap.nic.in',NULL,'["Only for those not getting any pension", "Grains collected monthly from PDS shop", "Annual verification of eligibility", "10 kg per beneficiary per month (not per family)"]',0,NULL,'["food", "senior", "destitute", "free grains"]','65');
